import{c as t,Q as a,j as r,m as o}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"安装选择","description":"","frontmatter":{},"headers":[],"relativePath":"zh/installation/index.md","filePath":"zh/installation/index.md","lastUpdated":1778736656000}'),d={name:"zh/installation/index.md"};function l(n,e,s,i,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="安装选择" tabindex="-1">安装选择 <a class="header-anchor" href="#安装选择" aria-label="Permalink to &quot;安装选择&quot;">​</a></h1><p>Memoh 有两种分发方式：面向个人/本地使用的 Desktop 桌面版，以及面向长期在线和多人使用的 Server Deploy。先选对形态，再看具体安装步骤。</p><table tabindex="0"><thead><tr><th>场景</th><th>选择</th><th>原因</th></tr></thead><tbody><tr><td>个人电脑、本地记忆、快速试用、单用户工作流</td><td><a href="/zh/installation/desktop.html">Desktop 桌面版</a></td><td>App 会自己启动本地服务、embedded Qdrant、本地存储和 bundled CLI。</td></tr><tr><td>共享服务器、远程访问、生产长期在线、对接 Telegram/Discord/飞书/微信/邮件等渠道</td><td><a href="/zh/installation/docker.html">Server Deploy</a></td><td>Docker Compose 或 Kubernetes 栈会持续运行后端、网页端、数据库、记忆服务和 workspace runtime。</td></tr></tbody></table><h2 id="desktop-桌面版" tabindex="-1">Desktop 桌面版 <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to &quot;Desktop 桌面版&quot;">​</a></h2><p>Desktop 适合把 Memoh 当成本地应用使用。它会管理 <code>127.0.0.1:18731</code> 上的本地 <code>memoh-server</code>，准备本地存储，启动 embedded Qdrant，并自动连接界面。</p><p>如果机器人需要在你的电脑离线时继续服务外部渠道，请改用 Server Deploy。</p><h2 id="server-deploy" tabindex="-1">Server Deploy <a class="header-anchor" href="#server-deploy" aria-label="Permalink to &quot;Server Deploy&quot;">​</a></h2><p>Server Deploy 适合多人、远程、长期在线或多租户场景。机器人需要持续接入 Telegram、Discord、飞书、微信、公众号、邮件等外部渠道时，也应该用这一形态。</p><p>一般从 <a href="/zh/installation/docker.html">Server Deploy</a> 的 Docker Compose 部署开始；如果你需要集群里的 workspace Pod/PVC，再看 <a href="/zh/installation/kubernetes.html">Kubernetes 部署</a>。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/zh/installation/workspace-backends.html">Workspace backend</a> 解释 Docker、Kubernetes、containerd、Apple 和本地 workspace 的差异。</li><li><a href="/zh/installation/sqlite.html">SQLite 部署</a> 适合更轻量的单节点 server 部署。</li></ul>',11)])])}const k=t(d,[["render",l]]);export{m as __pageData,k as default};
